mapper.select:
/*	설 명 : 사용자조회	*/
SELECT	*
FROM 	TB_LMS_USER USR
WHERE 	USER_ID = #{userId}

/*  설 명 : 등록된사용자들조회 - 대표아이디로등록된사용자들조회 */
SELECT	*
FROM 	TB_LMS_USER USR
WHERE 	USER_RPRS_ID = #{userRprsId}

/*  설 명 : 등록된사용자아이디들조회 - 대표아이디로등록된사용자아이디들조회 */
SELECT	USER_ID
FROM 	TB_LMS_USER USR
WHERE 	USER_RPRS_ID = #{userRprsId}

/* 설 명 : 교수별과목에서 수강생별과목에서 기관아이디조회 */ SELECT ORG_ID, ORGNM, USER_TYCD FROM ( SELECT O.ORG_ID, O.ORGNM, S.SBJCT_ID, S.SBJCTNM, 'PROF' AS USER_TYCD FROM TB_LMS_SBJCT S JOIN TB_LMS_SMSTR_CHRT SC ON S.SMSTR_CHRT_ID = SC.SMSTR_CHRT_ID JOIN TB_LMS_ORG O ON SC.ORG_ID = O.ORG_ID WHERE 1 = 1
AND S.PROF_ID IN
#{id}
AND 1 = 2 /* 리스트가 비어있을 경우 조회를 방지하기 위한 조건 */
UNION ALL SELECT O.ORG_ID, O.ORGNM, S.SBJCT_ID, S.SBJCTNM, 'STDNT' AS USER_TYCD FROM TB_LMS_ATNDLC A JOIN TB_LMS_SBJCT S ON A.SBJCT_ID = S.SBJCT_ID JOIN TB_LMS_SMSTR_CHRT SC ON S.SMSTR_CHRT_ID = SC.SMSTR_CHRT_ID JOIN TB_LMS_ORG O ON SC.ORG_ID = O.ORG_ID WHERE 1 = 1
AND A.USER_ID IN
#{id}
AND 1 = 2
) GROUP BY ORG_ID, ORGNM, USER_TYCD ORDER BY ORG_ID
